using namespace adsk::core;
using namespace adsk::fusion;

Ptr ui;

extern "C" XI_EXPORT bool run(const char* context)
{
    Ptr app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;

    Ptr documents = app->documents();
    if (!documents)
        return false;

    Ptr doc = documents->add(DocumentTypes::FusionDesignDocumentType);
    if (!doc)
        return false;

    Ptr product = app->activeProduct();
    if (!product)
        return false;

    Ptr design = product;
    if (!design)
        return false;

    // Get the root component of the active design
    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    // Create sketch
    Ptr sketches = rootComp->sketches();
    if (!sketches)
        return false;
    Ptr xz = rootComp->xZConstructionPlane();
    if (!xz)
        return false;
    Ptr sketch = sketches->add(xz);
    if (!sketch)
        return false;
    Ptr sketchCurves = sketch->sketchCurves();
    if (!sketchCurves)
        return false;
    Ptr sketchCircles = sketchCurves->sketchCircles();
    if (!sketchCircles)
        return false;
    Ptr centerPoint = Point3D::create(0, 0, 0);
    if (!centerPoint)
        return false;
    Ptr circle = sketchCircles->addByCenterRadius(centerPoint, 3.0);
    if (!circle)
        return false;

    // Get the profile defined by the circle.
    Ptr profs = sketch->profiles();
    if (!profs)
        return false;
    Ptr prof = profs->item(0);
    if (!prof)
        return false;

    // Create a vertical sketch and add two lines on it
    Ptr yz = rootComp->yZConstructionPlane();
    if (!yz)
        return false;
    Ptr sketchVertical = sketches->add(yz);
    if (!sketchVertical)
        return false;
    Ptr sketchCurvesVertical = sketchVertical->sketchCurves();
    if (!sketchCurvesVertical)
        return false;
    Ptr sketchLines = sketchCurvesVertical->sketchLines();
    if (!sketchLines)
        return false;
    Ptr startPt = Point3D::create(0, 0, 0);
    if (!startPt)
        return false;
    Ptr midPt = Point3D::create(0, 3, 0);
    if (!midPt)
        return false;
    Ptr endPt = Point3D::create(2, 6, 0);
    if (!endPt)
        return false;
    Ptr line1 = sketchLines->addByTwoPoints(startPt, midPt);
    if (!line1)
        return false;
    Ptr line2 = sketchLines->addByTwoPoints(midPt, endPt);
    if (!line2)
        return false;

    // Merge the two lines
    Ptr line1EndPt = line1->endSketchPoint();
    if (!line1EndPt)
        return false;
    Ptr line2StartPt = line2->startSketchPoint();
    if (!line2StartPt)
        return false;
    line1EndPt->merge(line2StartPt);

    // Create a path and let it find connected curves automatically
    Ptr feats = rootComp->features();
    if (!feats)
        return false;
    Ptr path = feats->createPath(line1);
    if (!path)
        return false;

    // Create a sweep input
    Ptr sweeps = feats->sweepFeatures();
    if (!sweeps)
        return false;
    Ptr sweepInput = sweeps->createInput(prof, path, FeatureOperations::NewBodyFeatureOperation);
    if (!sweepInput)
        return false;

    Ptr taper = ValueInput::createByString("5.0 deg");
    Ptr twist = ValueInput::createByString("10.0 deg");

    // Create the sweep.
    Ptr sweep = sweeps->add(sweepInput);
    if (!sweep)
        return false;

    // Get taperAngle and twistAngle from sweep feature
    Ptr taperParam = sweep->taperAngle();
    if (!taperParam)
        return false;

    Ptr twistParam = sweep->twistAngle();
    if (!twistParam)
        return false;


    return true;
}
